import React, { useState } from 'react';
import { MapContainer, TileLayer, Marker, Popup, useMap } from 'react-leaflet';
import L from 'leaflet';
import { Trash2, Store, Plus, X, MapPin, Search, Edit2 } from 'lucide-react';

// --- CONFIGURACIÓN DE ICONOS ---
import markerIcon from 'leaflet/dist/images/marker-icon.png';
import markerShadow from 'leaflet/dist/images/marker-shadow.png';
let DefaultIcon = L.icon({
    iconUrl: markerIcon,
    shadowUrl: markerShadow,
    iconSize: [25, 41],
    iconAnchor: [12, 41]
});
L.Marker.prototype.options.icon = DefaultIcon;

function ChangeView({ center }) {
  const map = useMap();
  map.setView(center, 16);
  return null;
}

const Dashboard = () => {
  const [locales, setLocales] = useState([
    { id: 1, nombre: "Mr. Drink", direccion: "Av. Manuel Belgrano 2800, Tucumán", coords: [-26.816, -65.230] }
  ]);
  
  const [showModal, setShowModal] = useState(false);
  const [isEditing, setIsEditing] = useState(false);
  const [currentId, setCurrentId] = useState(null);
  const [loading, setLoading] = useState(false);
  
  const [formLocal, setFormLocal] = useState({ 
    nombre: '', 
    direccion: '', 
    coords: [-26.816, -65.216] 
  });

  // ABRIR PARA CREAR NUEVO
  const handleOpenCreate = () => {
    setIsEditing(false);
    setFormLocal({ nombre: '', direccion: '', coords: [-26.8167, -65.2167] });
    setShowModal(true);
  };

  // ABRIR PARA EDITAR EXISTENTE
  const handleOpenEdit = (local) => {
    setIsEditing(true);
    setCurrentId(local.id);
    setFormLocal({ ...local });
    setShowModal(true);
  };

  const buscarDireccion = async () => {
    if (!formLocal.direccion) return;
    setLoading(true);
    try {
      const response = await fetch(
        `https://nominatim.openstreetmap.org/search?format=json&q=${encodeURIComponent(formLocal.direccion)}`
      );
      const data = await response.json();
      if (data && data.length > 0) {
        setFormLocal({ ...formLocal, coords: [parseFloat(data[0].lat), parseFloat(data[0].lon)] });
      }
    } catch (error) { console.error(error); }
    setLoading(false);
  };

  const guardarLocal = (e) => {
    e.preventDefault();
    if (isEditing) {
      setLocales(locales.map(l => l.id === currentId ? { ...formLocal } : l));
    } else {
      setLocales([...locales, { ...formLocal, id: Date.now() }]);
    }
    setShowModal(false);
  };

  return (
    <div style={{ display: 'flex', height: 'calc(100vh - 75px)', overflow: 'hidden', position: 'relative' }}>
      
      {/* SIDEBAR */}
      <div style={sidebarStyle}>
        <h2 style={{ fontSize: '1.5rem', marginBottom: '5px' }}>Mis Locales</h2>
        <div style={listaContenedor}>
          {locales.map(local => (
            <div key={local.id} style={cardLocal}>
              <div style={iconBox}><Store size={20} color="#e67e22" /></div>
              <div style={{ flex: 1 }}>
                <h4 style={{ margin: 0 }}>{local.nombre}</h4>
                <p style={{ margin: 0, fontSize: '0.8rem', color: '#64748b' }}>{local.direccion}</p>
              </div>
              <div style={{ display: 'flex', gap: '5px' }}>
                <button onClick={() => handleOpenEdit(local)} style={btnEdit}><Edit2 size={16} /></button>
                <button onClick={() => setLocales(locales.filter(l => l.id !== local.id))} style={btnBorrar}><Trash2 size={16} /></button>
              </div>
            </div>
          ))}
        </div>
        <button onClick={handleOpenCreate} style={btnNuevaSucursal}><Plus size={20} /> Nueva Sucursal</button>
      </div>

      {/* MAPA */}
      <div style={{ flex: 1 }}>
        <MapContainer center={formLocal.coords} zoom={14} style={{ height: '100%', width: '100%' }}>
          <ChangeView center={formLocal.coords} />
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" />
          {locales.map(local => (
            <Marker key={local.id} position={local.coords}>
              <Popup><strong>{local.nombre}</strong></Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>

      {/* MODAL EDITABLE */}
      {showModal && (
        <div style={modalOverlay}>
          <div style={modalContent}>
            <div style={modalHeader}>
              <h3>{isEditing ? 'Editar Sucursal' : 'Nueva Sucursal'}</h3>
              <X onClick={() => setShowModal(false)} style={{ cursor: 'pointer' }} />
            </div>
            <form onSubmit={guardarLocal}>
              <label style={labelStyle}>Nombre del Local</label>
              <input style={inputStyle} value={formLocal.nombre} required onChange={(e) => setFormLocal({...formLocal, nombre: e.target.value})} />
              
              <label style={labelStyle}>Dirección (Para búsqueda aproximada)</label>
              <div style={{ display: 'flex', gap: '10px', marginBottom: '15px' }}>
                <input style={{ ...inputStyle, marginBottom: 0 }} value={formLocal.direccion} onChange={(e) => setFormLocal({...formLocal, direccion: e.target.value})} />
                <button type="button" onClick={buscarDireccion} style={btnCheck}><Search size={18} /></button>
              </div>

              <label style={labelStyle}>Coordenadas Manuales (Precisión Total)</label>
              <div style={{ display: 'flex', gap: '10px', marginBottom: '20px' }}>
                <div style={{ flex: 1 }}>
                  <span style={miniLabel}>Latitud</span>
                  <input 
                    style={inputStyle} 
                    type="number" step="any"
                    value={formLocal.coords[0]} 
                    onChange={(e) => setFormLocal({...formLocal, coords: [parseFloat(e.target.value), formLocal.coords[1]]})}
                  />
                </div>
                <div style={{ flex: 1 }}>
                  <span style={miniLabel}>Longitud</span>
                  <input 
                    style={inputStyle} 
                    type="number" step="any"
                    value={formLocal.coords[1]} 
                    onChange={(e) => setFormLocal({...formLocal, coords: [formLocal.coords[0], parseFloat(e.target.value)]})}
                  />
                </div>
              </div>

              <button type="submit" style={btnNuevaSucursal} disabled={loading}>
                {isEditing ? 'Actualizar Cambios' : 'Guardar Sucursal'}
              </button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

